'use client';

import { useState } from 'react';
import { Candidate } from '@/lib/types';
import Link from 'next/link';
import { StatusBadge } from './StatusBadge';
import { Search, Filter, Play, ArrowRight, Trash2, UserPlus, FileText } from 'lucide-react';
import { deleteCandidate } from '@/lib/actions';
import { useRouter } from 'next/navigation';

export function CandidateList({ initialCandidates, userRole }: { initialCandidates: Candidate[], userRole?: string }) {
    const [search, setSearch] = useState('');
    const [statusFilter, setStatusFilter] = useState('All');
    const [trackFilter, setTrackFilter] = useState('All');
    const router = useRouter();

    const filtered = initialCandidates.filter(c => { // Changed candidates to initialCandidates
        const matchesSearch = c.name.toLowerCase().includes(search.toLowerCase());
        const matchesStatus = statusFilter === 'All' || c.status === statusFilter;
        const matchesTrack = trackFilter === 'All' || c.track === trackFilter;
        return matchesSearch && matchesStatus && matchesTrack;
    });

    const handleDelete = async (id: string) => {
        if (confirm('Are you sure you want to delete this candidate?')) {
            await deleteCandidate(id);
            router.refresh();
        }
    };

    return (
        <div className="space-y-6">
            <div className="flex flex-col md:flex-row gap-4">
                <div className="relative flex-1">
                    <Search className="absolute left-3 top-2.5 text-slate-400" size={18} />
                    <input
                        type="text"
                        placeholder="Search candidates..."
                        className="w-full pl-10 pr-4 py-2 border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
                        value={search}
                        onChange={(e) => setSearch(e.target.value)}
                    />
                </div>

                <select
                    className="px-4 py-2 border border-slate-200 rounded-lg bg-white"
                    value={statusFilter}
                    onChange={(e) => setStatusFilter(e.target.value)}
                >
                    <option value="All">All Statuses</option>
                    <option value="Pending">Pending</option>
                    <option value="In-Progress">In-Progress</option>
                    <option value="Interviewed">Interviewed</option>
                    <option value="Selected">Selected</option>
                    <option value="Rejected">Rejected</option>
                </select>

                <select
                    className="px-4 py-2 border border-slate-200 rounded-lg bg-white"
                    value={trackFilter}
                    onChange={(e) => setTrackFilter(e.target.value)}
                >
                    <option value="All">All Tracks</option>
                    <option value="Web">Web</option>
                    <option value="AI-ML">AI-ML</option>
                    <option value="Event-Tech">Event-Tech</option>
                    <option value="General">General</option>
                </select>
            </div>

            <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
                <table className="w-full text-left border-collapse">
                    <thead className="bg-slate-50 border-b border-slate-200">
                        <tr>
                            <th className="p-4 text-left font-bold text-slate-500">Candidate</th>
                            <th className="p-4 text-left font-bold text-slate-500">Track/Year</th>
                            <th className="p-4 text-left font-bold text-slate-500">Rating</th>
                            <th className="p-4 text-left font-bold text-slate-500">Recommendation</th>
                            <th className="p-4 text-left font-bold text-slate-500">Status</th>
                            <th className="p-4 text-left font-bold text-slate-500">Actions</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-100">
                        {filtered.map((candidate) => (
                            <tr key={candidate.id} className="hover:bg-slate-50 transition-colors group">
                                <td className="p-4">
                                    <div className="font-bold text-slate-900 capitalize">{candidate.name}</div>
                                    <div className="text-xs text-slate-500">{candidate.email}</div>
                                </td>
                                <td className="p-4">
                                    <div className="font-semibold text-slate-700">{candidate.track}</div>
                                    <div className="text-xs text-slate-500">{candidate.branch} • {candidate.year}</div>
                                </td>
                                <td className="p-4">
                                    {candidate.averageScore ? (
                                        <div className="font-bold text-blue-600 text-lg">{candidate.averageScore}</div>
                                    ) : (
                                        <span className="text-slate-300">-</span>
                                    )}
                                </td>
                                <td className="p-4">
                                    {candidate.recommendation ? (
                                        <span className="text-xs px-2 py-1 bg-slate-100 rounded border border-slate-200 font-medium">
                                            {candidate.recommendation}
                                        </span>
                                    ) : (
                                        <span className="text-slate-300">-</span>
                                    )}
                                </td>
                                <td className="p-4">
                                    <StatusBadge status={candidate.status} />
                                </td>
                                <td className="p-4">
                                    <div className="flex items-center gap-2 opacity-100 sm:opacity-0 sm:group-hover:opacity-100 transition-opacity">
                                        <Link
                                            href={`/interview/${candidate.id}`}
                                            className="p-2 bg-slate-900 text-white rounded hover:bg-slate-700"
                                            title="Start Interview"
                                        >
                                            <Play size={14} />
                                        </Link>
                                        <Link
                                            href={`/reports/${candidate.id}`}
                                            className="p-2 bg-blue-50 text-blue-600 rounded hover:bg-blue-100"
                                            title="View Report"
                                        >
                                            <FileText size={14} />
                                        </Link>
                                        <Link
                                            href={`/candidates/${candidate.id}/edit`}
                                            className="p-2 bg-slate-50 text-slate-600 rounded hover:bg-slate-200"
                                            title="Edit Details"
                                        >
                                            <UserPlus size={14} />
                                        </Link>
                                        <button
                                            onClick={() => handleDelete(candidate.id)}
                                            className="p-2 text-red-400 hover:text-red-600 hover:bg-red-50 rounded"
                                            title="Delete"
                                        >
                                            <Trash2 size={14} />
                                        </button>
                                    </div>
                                </td>
                            </tr>
                        ))}
                        {filtered.length === 0 && (
                            <tr>
                                <td colSpan={6} className="px-6 py-8 text-center text-slate-500">
                                    No candidates found.
                                </td>
                            </tr>
                        )}
                    </tbody>
                </table>
            </div>
        </div>
    );
}
