'use client';

import { Candidate } from '@/lib/types';
import { Download } from 'lucide-react';

export function ExportButton({ candidates }: { candidates: Candidate[] }) {
    const handleExport = () => {
        // Define headers
        const headers = [
            'ID', 'Name', 'Email', 'Phone', 'Branch', 'Year', 'Track', 'Why IEEE',
            'Status', 'Average Score (50)', 'Final Rating (10)', 'Tags',
            'Interviewer 1 Name', 'Inv 1 Score', 'Inv 1 Rec',
            'Interviewer 2 Name', 'Inv 2 Score', 'Inv 2 Rec',
            'Notes'
        ];

        // Map data to rows
        const rows = candidates.map(c => [
            c.id,
            `"${c.name}"`,
            c.email,
            c.phone,
            c.branch,
            c.year,
            c.track,
            `"${c.whyIeee.replace(/"/g, '""')}"`, // Escape quotes
            c.status,
            c.averageScore,
            c.finalRatingAverage,
            `"${c.tags.join(', ')}"`,
            c.scores.interviewer1?.interviewerName || '',
            c.scores.interviewer1?.total || '',
            c.scores.interviewer1?.recommendation || '',
            c.scores.interviewer2?.interviewerName || '',
            c.scores.interviewer2?.total || '',
            c.scores.interviewer2?.recommendation || '',
            `"${c.notes.replace(/"/g, '""')}"`
        ]);

        const csvContent = [
            headers.join(','),
            ...rows.map(row => row.join(','))
        ].join('\n');

        const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
        const url = URL.createObjectURL(blob);
        const link = document.createElement('a');
        link.href = url;
        link.setAttribute('download', 'ieee_candidates_export.csv');
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    };

    return (
        <button
            onClick={handleExport}
            className="flex items-center gap-2 px-4 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700 font-bold text-sm shadow-sm transition-all active:scale-95"
        >
            <Download size={16} /> Export CSV
        </button>
    );
}
